package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSet() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        boolean result = csvFormat.isCommentMarkerSet();

        // Then
        assertFalse(result);
    }

    @Test
    public void testIsCommentMarkerSetWithCommentMarker() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        setCommentMarker(csvFormat, '#');

        // When
        boolean result = csvFormat.isCommentMarkerSet();

        // Then
        assertTrue(result);
    }

    private void setCommentMarker(CSVFormat csvFormat, char commentMarker) throws NoSuchFieldException, IllegalAccessException {
        Field field = CSVFormat.class.getDeclaredField("commentMarker");
        field.setAccessible(true);
        field.set(csvFormat, commentMarker);
    }
}
